t.script:

let certOriginalData = {};

function certEnableEdit() {
    certStoreOriginal();
    const inputs = document.querySelectorAll('#certificationForm input, #certificationForm textarea');
    inputs.forEach(input => {
        if (input.type !== 'hidden') {
            input.removeAttribute('readonly');
            input.removeAttribute('disabled');
        }
    });
    document.getElementById('certFormActions').style.display = 'block';
    /* ── Reset disclaimer & save button ── */
    const disc = document.getElementById('certDisclaimer');
    if (disc) disc.checked = false;
    const btn = document.getElementById('certSaveBtn');
    if (btn) { btn.disabled = true; btn.style.opacity = '0.6'; }
}

function certStoreOriginal() {
    const form = document.getElementById('certificationForm');
    const formData = new FormData(form);
    certOriginalData = {};
    for (let [key, value] of formData.entries()) {
        certOriginalData[key] = value;
    }
}

function certCancelEdit() {
    for (let [key, value] of Object.entries(certOriginalData)) {
        const input = document.querySelector(`[name="${key}"]`);
        if (input && input.type !== 'hidden' && input.type !== 'file') {
            input.value = value;
        }
    }
    certDisableEdit();
    certShowMessage('Changes cancelled.', 'info');
}

function certDisableEdit() {
    const inputs = document.querySelectorAll('#certificationForm input, #certificationForm textarea');
    inputs.forEach(input => {
        if (input.type !== 'hidden' && input.type !== 'file') {
            input.setAttribute('readonly', 'readonly');
        }
    });
    document.getElementById('certFormActions').style.display = 'none';
    /* ── Reset disclaimer & save button ── */
    const disc = document.getElementById('certDisclaimer');
    if (disc) disc.checked = false;
    const btn = document.getElementById('certSaveBtn');
    if (btn) { btn.disabled = true; btn.style.opacity = '0.6'; }
}

/* ── ONLY NEW FUNCTION ── */
function toggleCertSaveBtn() {
    const checked = document.getElementById('certDisclaimer').checked;
    const btn = document.getElementById('certSaveBtn');
    btn.disabled = !checked;
    btn.style.opacity = checked ? '1' : '0.6';
}

document.getElementById('certificationForm').addEventListener('submit', function (e) {
    e.preventDefault();
    /* ── Guard: disclaimer must be checked ── */
    const disc = document.getElementById('certDisclaimer');
    if (disc && !disc.checked) {
        certShowMessage('Please read and accept the Employee Disclaimer before saving.', 'error');
        return;
    }
    const formData = new FormData(this);
    fetch('/my/employee/certification', {
        method: 'POST',
        body: formData
    })
    .then(response => response.json())
    .then(data => {
        if (data.success) {
            certShowMessage('Certifications updated successfully!', 'success');
            certDisableEdit();
        } else {
            certShowMessage('Error: ' + (data.error || 'Unknown error'), 'error');
        }
    })
    .catch(error => {
        console.error('Error:', error);
        certShowMessage('Network error. Please try again.', 'error');
    });
});

function certShowMessage(text, type) {
    const container = document.getElementById('certMessageContainer');
    const successMsg = document.getElementById('certSuccessMessage');
    const errorMsg = document.getElementById('certErrorMessage');
    successMsg.style.display = 'none';
    errorMsg.style.display = 'none';
    successMsg.classList.remove('show');
    errorMsg.classList.remove('show');
    if (type === 'success') {
        document.getElementById('certSuccessText').textContent = text;
        successMsg.style.display = 'block';
        successMsg.classList.add('show');
    } else {
        document.getElementById('certErrorText').textContent = text;
        errorMsg.style.display = 'block';
        errorMsg.classList.add('show');
    }
    container.style.display = 'block';
    container.scrollIntoView({behavior: 'smooth'});
    setTimeout(() => {
        successMsg.classList.remove('show');
        errorMsg.classList.remove('show');
    }, 5000);
}
